1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const sortCells = (cells: [number, number][]) =>
16	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
17	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
18	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
20	  });
21	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
22	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
23	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
24	});
