1	export type Cell = [number, number];
2	
3	export const nextGeneration = (cells: Cell[]): Cell[] => {
4	  const countNeighbors = (x: number, y: number): number =>
5	    cells.filter(([cx, cy]) => {
6	      const dx = Math.abs(cx - x);
7	      const dy = Math.abs(cy - y);
8	      return (dx !== 0 || dy !== 0) && dx <= 1 && dy <= 1;
9	    }).length;
10	
11	  return cells.filter(([x, y]) => {
12	    const neighborCount = countNeighbors(x, y);
13	    return neighborCount === 2 || neighborCount === 3;
14	  });
15	};
